 1	import React, { Dispatch, FC, MouseEvent, SetStateAction } from 'react';
 2	
 3	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { FormGroup, SelectOption } from '@patternfly/react-core';
 6	
 7	import { interfaceModelType } from '../utils/constants';
 8	
 9	type NetworkInterfaceModelSelectProps = {
10	  interfaceModel: string;
11	  setInterfaceModel: Dispatch<SetStateAction<string>>;
12	};
13	
14	const NetworkInterfaceModelSelect: FC<NetworkInterfaceModelSelectProps> = ({
15	  interfaceModel,
16	  setInterfaceModel,
17	}) => {
18	  const { t } = useKubevirtTranslation();
19	
20	  const interfaceModelOptions = {
21	    e1000e: {
22	      description: t(
23	        'Supported by most operating systems including Windows out of the box. Offers lower performance compared to virtio.',
24	      ),
25	      id: interfaceModelType.E1000E,
26	      name: t('e1000e'),
27	    },
28	    virtio: {
29	      description: t(
30	        'Optimized for best performance. Supported by most Linux distributions. Windows requires additional drivers to use this model',
31	      ),
32	      id: interfaceModelType.VIRTIO,
33	      name: t('virtio'),
34	    },
35	  };
36	
37	  const handleChange = (event: MouseEvent<HTMLSelectElement>, value: string) => {
38	    event.preventDefault();
39	    setInterfaceModel(value);
40	  };
41	
42	  return (
43	    <FormGroup fieldId="model" label={t('Model')}>
44	      <div data-test-id="model-select">
45	        <FormPFSelect
46	          onSelect={handleChange}
47	          selected={interfaceModel}
48	          selectedLabel={interfaceModelOptions[interfaceModel].name}
49	          toggleProps={{ isFullWidth: true }}
50	        >
51	          {Object.values(interfaceModelOptions)?.map(({ description, id, name }) => (
52	            <SelectOption
53	              data-test-id={`model-select-${id}`}
54	              description={description}
55	              key={id}
56	              value={id}
57	            >
58	              {name}
59	            </SelectOption>
60	          ))}
61	        </FormPFSelect>
62	      </div>
63	    </FormGroup>
64	  );
65	};
66	
67	export default NetworkInterfaceModelSelect;

